import React from "react";
import MessageForm from "./MessageForm";

const formatTime = (dateString) => new Date(dateString).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

export default function ChatInterface({ activeRoom, messages, roomUsers, currentUser, onSendMessage }) {
  if (!activeRoom) {
    return <section className="chat-interface glass empty-chat"><h3>Select a room to start chatting</h3><p>Join a room from the left panel or create a new one.</p></section>;
  }

  return (
    <section className="chat-interface glass">
      <header className="chat-head">
        <div><h3>#{activeRoom.name}</h3><p>{activeRoom.description || "No room description yet"}</p></div>
        <div className="room-user-chips">{roomUsers.map((u) => <span key={u.id || u._id} className="chip">{u.username}</span>)}</div>
      </header>

      <div className="message-list">
        {messages.map((message) => {
          const ownMessage = (message.user?._id || message.user?.id) === currentUser?.id;
          if (message.system) {
            return <div className="system-message" key={message._id || message.createdAt + message.content}><span>{message.content}</span><small>{formatTime(message.createdAt)}</small></div>;
          }
          return (
            <article key={message._id || message.createdAt + message.content} className={ownMessage ? "msg own" : "msg"}>
              <div className="msg-meta"><strong>{message.user?.username || "Unknown"}</strong><small>{formatTime(message.createdAt)}</small></div>
              <p>{message.content}</p>
            </article>
          );
        })}
      </div>

      <MessageForm onSend={onSendMessage} />
    </section>
  );
}
